def gen(rng, size):
    n = max(2, min(size, 20000))
    edges = []
    for i in range(1, n):
        p = rng.randint(0, i - 1)
        edges.append([p, i])
    cost = []
    for _ in range(n):
        v = rng.randint(1, 10000)
        if rng.random() < 0.5:
            v = -v
        cost.append(v)
    return [edges, cost]

