from itertools import combinations

class Solution:
    def placedCoins(self, edges, cost):
        n = len(cost)
        adj = [[] for _ in range(n)]
        for a, b in edges:
            adj[a].append(b)
            adj[b].append(a)
        parent = [-1] * n
        order = []
        visited = [False] * n
        stack = [0]
        visited[0] = True
        while stack:
            u = stack.pop()
            order.append(u)
            for v in adj[u]:
                if not visited[v]:
                    visited[v] = True
                    parent[v] = u
                    stack.append(v)
        children = [[] for _ in range(n)]
        for v in range(n):
            if parent[v] != -1:
                children[parent[v]].append(v)
        subtree = [None] * n
        for u in reversed(order):
            nodes = [u]
            for c in children[u]:
                nodes.extend(subtree[c])
            subtree[u] = nodes
        coin = [0] * n
        for u in range(n):
            nodes = subtree[u]
            if len(nodes) < 3:
                coin[u] = 1
            else:
                vals = [cost[x] for x in nodes]
                best = max(a * b * c for a, b, c in combinations(vals, 3))
                coin[u] = max(best, 0)
        return coin

