var placedCoins = function(edges, cost) {
    const n = cost.length;
    const adj = Array.from({ length: n }, () => []);
    for (const [a, b] of edges) {
        adj[a].push(b);
        adj[b].push(a);
    }
    const parent = new Array(n).fill(-1);
    const order = [];
    const visited = new Array(n).fill(false);
    const stack = [0];
    visited[0] = true;
    while (stack.length) {
        const u = stack.pop();
        order.push(u);
        for (const v of adj[u]) {
            if (!visited[v]) {
                visited[v] = true;
                parent[v] = u;
                stack.push(v);
            }
        }
    }
    const children = Array.from({ length: n }, () => []);
    for (let v = 0; v < n; v++) {
        if (parent[v] !== -1) children[parent[v]].push(v);
    }
    const size = new Array(n).fill(1);
    const top3 = new Array(n).fill(null);
    const bot3 = new Array(n).fill(null);
    const coin = new Array(n).fill(0);
    for (let i = order.length - 1; i >= 0; i--) {
        const u = order[i];
        let t = [cost[u]];
        let b = [cost[u]];
        let sz = 1;
        for (const c of children[u]) {
            sz += size[c];
            t = t.concat(top3[c]);
            b = b.concat(bot3[c]);
        }
        t.sort((x, y) => y - x);
        if (t.length > 3) t = t.slice(0, 3);
        b.sort((x, y) => x - y);
        if (b.length > 3) b = b.slice(0, 3);
        size[u] = sz;
        top3[u] = t;
        bot3[u] = b;
        if (sz < 3) {
            coin[u] = 1;
        } else {
            const candidates = [];
            if (t.length >= 3) candidates.push(t[0] * t[1] * t[2]);
            if (b.length >= 2 && t.length >= 1) candidates.push(b[0] * b[1] * t[0]);
            coin[u] = Math.max(Math.max(...candidates), 0);
        }
    }
    return coin;
};
